    85→// lineCapture is an io.Writer that forwards writes to an optional passthrough
    86→// writer and records each complete line as a logEvent.
    87→type lineCapture struct {
    88→	out    io.Writer
    89→	evType string
    90→	mu     *sync.Mutex
    91→	events *[]logEvent
    92→	buf    []byte
    93→}
    94→
    95→func newLineCapture(out io.Writer, evType string, mu *sync.Mutex, events *[]logEvent) *lineCapture {
    96→	return &lineCapture{out: out, evType: evType, mu: mu, events: events}
    97→}
    98→
    99→func (lc *lineCapture) Write(p []byte) (int, error) {
   100→	n := len(p)
   101→	var writeErr error
   102→	if lc.out != nil {
   103→		_, writeErr = lc.out.Write(p)
   104→	}
   105→	lc.buf = append(lc.buf, p...)
   106→	for {
   107→		idx := bytes.IndexByte(lc.buf, '\n')
   108→		if idx < 0 {
   109→			break
   110→		}
   111→		line := string(lc.buf[:idx])
   112→		ts := time.Now()
   113→		lc.mu.Lock()
   114→		*lc.events = append(*lc.events, logEvent{TS: ts, Type: lc.evType, Line: line})
   115→		lc.mu.Unlock()
   116→		lc.buf = lc.buf[idx+1:]
   117→	}
   118→	return n, writeErr
   119→}
   120→
   121→func (lc *lineCapture) flush() {
   122→	if len(lc.buf) > 0 {
   123→		ts := time.Now()
   124→		lc.mu.Lock()
   125→		*lc.events = append(*lc.events, logEvent{TS: ts, Type: lc.evType, Line: string(lc.buf)})
   126→		lc.mu.Unlock()
   127→		lc.buf = nil
   128→	}
   129→}
