   153→// parseFooter scans output lines (last-first) for a valid kiln JSON footer.
   154→// Returns status, task_id, and true when found; empty strings and false otherwise.
   155→func parseFooter(output string) (status, taskID string, ok bool) {
   156→	lines := strings.Split(output, "\n")
   157→	for i := len(lines) - 1; i >= 0; i-- {
   158→		line := strings.TrimSpace(lines[i])
   159→		if !strings.Contains(line, `"kiln"`) {
   160→			continue
   161→		}
   162→		var env kilnFooterEnvelope
   163→		if err := json.Unmarshal([]byte(line), &env); err != nil {
   164→			continue
   165→		}
   166→		if env.Kiln.Status != "" {
   167→			return env.Kiln.Status, env.Kiln.TaskID, true
   168→		}
   169→	}
   170→	return "", "", false
   171→}
