   177→func run(args []string, stdout, stderr io.Writer) int {
   178→	if len(args) == 0 {
   179→		fmt.Fprintln(stderr, "usage: kiln <command> [flags]")
   180→		return 1
   181→	}
   182→
   183→	switch args[0] {
   184→	case "exec":
   185→		code, err := runExec(args[1:], stdout)
   186→		if err != nil {
   187→			fmt.Fprintf(stderr, "exec: %v\n", err)
   188→			var te *timeoutError
   189→			if errors.As(err, &te) {
   190→				return 20
   191→			}
   192→			var fe *footerError
   193→			if errors.As(err, &fe) {
   194→				return 10
   195→			}
   196→			return 1
   197→		}
   198→		return code
   199→	case "gen-make":
   200→		if err := runGenMake(args[1:]); err != nil {
   201→			fmt.Fprintf(stderr, "gen-make: %v\n", err)
   202→			return 1
   203→		}
   204→		return 0
   205→	case "status":
   206→		if err := runStatus(args[1:], stdout); err != nil {
   207→			fmt.Fprintf(stderr, "status: %v\n", err)
   208→			return 1
   209→		}
   210→		return 0
   211→	case "validate-schema":
   212→		if err := runValidateSchema(args[1:], stdout); err != nil {
   213→			fmt.Fprintf(stderr, "validate-schema: %v\n", err)
   214→			return 1
   215→		}
   216→		return 0
   217→	case "validate-cycles":
   218→		if err := runValidateCycles(args[1:], stdout); err != nil {
   219→			fmt.Fprintf(stderr, "validate-cycles: %v\n", err)
   220→			return 1
   221→		}
   222→		return 0
   223→	default:
   224→		fmt.Fprintf(stderr, "unknown command: %s\n", args[0])
   225→		return 1
   226→	}
   227→}
