   229→// Task represents a single entry in the tasks.yaml file.
   230→type Task struct {
   231→	ID      string   `yaml:"id"`
   232→	Prompt  string   `yaml:"prompt"`
   233→	Needs   []string `yaml:"needs"`
   234→	Timeout string   `yaml:"timeout,omitempty"`
   235→	Model   string   `yaml:"model,omitempty"`
   236→}
   237→
   238→// taskIDRegexp is the valid pattern for task IDs (kebab-case).
   239→var taskIDRegexp = regexp.MustCompile(`^[a-z0-9]+(?:-[a-z0-9]+)*$`)
   240→
   241→// loadTasks reads, parses, and validates a tasks.yaml file.
   242→// Unknown fields are rejected (strict schema).
   243→func loadTasks(path string) ([]Task, error) {
   244→	data, err := os.ReadFile(path)
   245→	if err != nil {
   246→		return nil, fmt.Errorf("failed to read tasks file: %w", err)
   247→	}
   248→
   249→	dec := yaml.NewDecoder(bytes.NewReader(data))
   250→	dec.KnownFields(true)
   251→
   252→	var tasks []Task
   253→	if decErr := dec.Decode(&tasks); decErr != nil {
   254→		if decErr == io.EOF {
   255→			return nil, fmt.Errorf("no tasks found in %s", path)
   256→		}
   257→		return nil, fmt.Errorf("failed to parse tasks file: %w", decErr)
   258→	}
   259→
   260→	if len(tasks) == 0 {
   261→		return nil, fmt.Errorf("no tasks found in %s", path)
   262→	}
   263→
   264→	seen := make(map[string]bool)
   265→	for i, t := range tasks {
   266→		if t.ID == "" {
   267→			return nil, fmt.Errorf("task at index %d: id is required", i)
   268→		}
   269→		if !taskIDRegexp.MatchString(t.ID) {
   270→			return nil, fmt.Errorf("task %q: id must be kebab-case", t.ID)
   271→		}
   272→		if seen[t.ID] {
   273→			return nil, fmt.Errorf("duplicate task id %q", t.ID)
   274→		}
   275→		seen[t.ID] = true
   276→		if t.Prompt == "" {
   277→			return nil, fmt.Errorf("task %q: prompt is required", t.ID)
   278→		}
   279→		if filepath.IsAbs(t.Prompt) {
   280→			return nil, fmt.Errorf("task %q: prompt must be a relative path, got %q", t.ID, t.Prompt)
   281→		}
   282→		for j, dep := range t.Needs {
   283→			if dep == "" {
   284→				return nil, fmt.Errorf("task %q: needs[%d] must not be empty", t.ID, j)
   285→			}
   286→		}
   287→	}
   288→
   289→	return tasks, nil
   290→}
