   292→func runValidateCycles(args []string, stdout io.Writer) error {
   293→	fs := flag.NewFlagSet("validate-cycles", flag.ContinueOnError)
   294→	tasksFile := fs.String("tasks", "", "path to tasks.yaml")
   295→
   296→	if err := fs.Parse(args); err != nil {
   297→		return err
   298→	}
   299→
   300→	if *tasksFile == "" {
   301→		return fmt.Errorf("--tasks is required")
   302→	}
   303→
   304→	tasks, err := loadTasks(*tasksFile)
   305→	if err != nil {
   306→		return err
   307→	}
   308→
   309→	// Build ID set for existence check and adjacency list in definition order.
   310→	idSet := make(map[string]bool, len(tasks))
   311→	adj := make(map[string][]string, len(tasks))
   312→	order := make([]string, 0, len(tasks))
   313→	for _, t := range tasks {
   314→		idSet[t.ID] = true
   315→		adj[t.ID] = t.Needs
   316→		order = append(order, t.ID)
   317→	}
   318→
   319→	// 1. Validate all dependency references exist.
   320→	for _, t := range tasks {
   321→		for _, dep := range t.Needs {
   322→			if !idSet[dep] {
   323→				return fmt.Errorf("task %q: unknown dependency %q", t.ID, dep)
   324→			}
   325→		}
   326→	}
   327→
   328→	// 2. Cycle detection via DFS with color marking.
   329→	// Colors: 0=white (unvisited), 1=gray (in current path), 2=black (fully visited).
   330→	color := make(map[string]int, len(tasks))
   331→	parent := make(map[string]string, len(tasks))
   332→
   333→	var cycleErr error
   334→
   335→	var dfs func(id string) bool
   336→	dfs = func(id string) bool {
   337→		color[id] = 1 // gray: on current DFS path
   338→		for _, dep := range adj[id] {
   339→			if color[dep] == 1 {
   340→				// Back edge found: dep is an ancestor on the current path.
   341→				// Reconstruct cycle: dep -> ... -> id -> dep
   342→				path := []string{}
   343→				cur := id
   344→				for cur != dep {
   345→					path = append(path, cur)
   346→					cur = parent[cur]
   347→				}
   348→				// path is [id, ..., child_of_dep] in reverse; reverse it.
   349→				for i, j := 0, len(path)-1; i < j; i, j = i+1, j-1 {
   350→					path[i], path[j] = path[j], path[i]
   351→				}
   352→				fullPath := append([]string{dep}, path...)
   353→				fullPath = append(fullPath, dep)
   354→				cycleErr = fmt.Errorf("cycle detected: %s", strings.Join(fullPath, " -> "))
   355→				return true
   356→			}
   357→			if color[dep] == 0 {
   358→				parent[dep] = id
   359→				if dfs(dep) {
   360→					return true
   361→				}
   362→			}
   363→		}
   364→		color[id] = 2 // black: fully explored
   365→		return false
   366→	}
   367→
   368→	for _, id := range order {
   369→		if color[id] == 0 {
   370→			if dfs(id) {
   371→				return cycleErr
   372→			}
   373→		}
   374→	}
   375→
   376→	fmt.Fprintln(stdout, "validate-cycles: OK")
   377→	return nil
   378→}
