   401→func runGenMake(args []string) error {
   402→	fs := flag.NewFlagSet("gen-make", flag.ContinueOnError)
   403→	tasksFile := fs.String("tasks", "", "path to tasks.yaml")
   404→	outFile := fs.String("out", "", "output path for targets.mk")
   405→
   406→	if err := fs.Parse(args); err != nil {
   407→		return err
   408→	}
   409→
   410→	if *tasksFile == "" {
   411→		return fmt.Errorf("--tasks is required")
   412→	}
   413→	if *outFile == "" {
   414→		return fmt.Errorf("--out is required")
   415→	}
   416→
   417→	tasks, err := loadTasks(*tasksFile)
   418→	if err != nil {
   419→		return err
   420→	}
   421→
   422→	var buf bytes.Buffer
   423→
   424→	// Collect all done targets
   425→	var allDone []string
   426→	for _, t := range tasks {
   427→		allDone = append(allDone, ".kiln/done/"+t.ID+".done")
   428→	}
   429→
   430→	// Phony all target
   431→	buf.WriteString(".PHONY: all\n")
   432→	buf.WriteString("all:")
   433→	for _, d := range allDone {
   434→		buf.WriteString(" " + d)
   435→	}
   436→	buf.WriteString("\n\n")
   437→
   438→	// Individual targets in definition order
   439→	for _, t := range tasks {
   440→		target := ".kiln/done/" + t.ID + ".done"
   441→		buf.WriteString(target + ":")
   442→		for _, dep := range t.Needs {
   443→			buf.WriteString(" .kiln/done/" + dep + ".done")
   444→		}
   445→		buf.WriteString("\n")
   446→		recipe := "$(KILN) exec --task-id " + t.ID + " --tasks " + *tasksFile
   447→		if t.Timeout != "" {
   448→			recipe += " --timeout " + t.Timeout
   449→		}
   450→		buf.WriteString("\t" + recipe + "\n")
   451→		buf.WriteString("\n")
   452→	}
   453→
   454→	if err := os.MkdirAll(filepath.Dir(*outFile), 0o755); err != nil {
   455→		return fmt.Errorf("failed to create output directory: %w", err)
   456→	}
   457→
   458→	if err := os.WriteFile(*outFile, buf.Bytes(), 0o644); err != nil {
   459→		return fmt.Errorf("failed to write output file: %w", err)
   460→	}
   461→
   462→	return nil
   463→}
