   465→// hasUnfinishedDeps returns true if any of the given dependency IDs are not in the doneSet.
   466→func hasUnfinishedDeps(needs []string, doneSet map[string]bool) bool {
   467→	for _, dep := range needs {
   468→		if !doneSet[dep] {
   469→			return true
   470→		}
   471→	}
   472→	return false
   473→}
