   475→func runStatus(args []string, stdout io.Writer) error {
   476→	fs := flag.NewFlagSet("status", flag.ContinueOnError)
   477→	tasksFile := fs.String("tasks", "", "path to tasks.yaml")
   478→
   479→	if err := fs.Parse(args); err != nil {
   480→		return err
   481→	}
   482→
   483→	if *tasksFile == "" {
   484→		return fmt.Errorf("--tasks is required")
   485→	}
   486→
   487→	tasks, err := loadTasks(*tasksFile)
   488→	if err != nil {
   489→		return err
   490→	}
   491→
   492→	// Build done set by checking for done markers
   493→	doneSet := make(map[string]bool)
   494→	for _, t := range tasks {
   495→		donePath := filepath.Join(".kiln", "done", t.ID+".done")
   496→		if _, err := os.Stat(donePath); err == nil {
   497→			doneSet[t.ID] = true
   498→		}
   499→	}
   500→
   501→	// Classify and print
   502→	var doneCount, runnableCount int
   503→	fmt.Fprintf(stdout, "%-30s %-10s %s\n", "TASK", "STATUS", "NEEDS")
   504→	fmt.Fprintf(stdout, "%-30s %-10s %s\n", "----", "------", "-----")
   505→
   506→	for _, t := range tasks {
   507→		var status string
   508→		if doneSet[t.ID] {
   509→			status = "done"
   510→			doneCount++
   511→		} else if hasUnfinishedDeps(t.Needs, doneSet) {
   512→			status = "blocked"
   513→		} else {
   514→			status = "runnable"
   515→			runnableCount++
   516→		}
   517→		needs := strings.Join(t.Needs, ", ")
   518→		if needs == "" {
   519→			needs = "-"
   520→		}
   521→		fmt.Fprintf(stdout, "%-30s %-10s %s\n", t.ID, status, needs)
   522→	}
   523→
   524→	fmt.Fprintf(stdout, "\n%d/%d tasks done, %d runnable\n", doneCount, len(tasks), runnableCount)
   525→	return nil
   526→}
