   558→func runExec(args []string, stdout io.Writer) (int, error) {
   559→	fs := flag.NewFlagSet("exec", flag.ContinueOnError)
   560→
   561→	taskID := fs.String("task-id", "", "task identifier")
   562→	promptFile := fs.String("prompt-file", "", "path to prompt file")
   563→	tasksFlag := fs.String("tasks", "", "path to tasks.yaml (resolves prompt and model from task definition)")
   564→	modelFlag := fs.String("model", "", "claude model to use (overrides KILN_MODEL env var)")
   565→	timeoutStr := fs.String("timeout", "15m", "maximum duration for the claude invocation")
   566→	retriesFlag := fs.Int("retries", 0, "number of additional attempts on retryable failures")
   567→	retryBackoffStr := fs.String("retry-backoff", "0s", "sleep duration between retry attempts")
   568→
   569→	if err := fs.Parse(args); err != nil {
   570→		return 0, err
   571→	}
   572→
   573→	if *taskID == "" {
   574→		return 0, fmt.Errorf("--task-id is required")
   575→	}
   576→
   577→	// Resolve prompt and model from tasks.yaml when --tasks is provided
   578→	var taskModel string
   579→	if *tasksFlag != "" {
   580→		tasks, err := loadTasks(*tasksFlag)
   581→		if err != nil {
   582→			return 0, err
